+    fn percentile_linear_series(sorted: &[f64], q: f64) -> f64 {
+        if sorted.len() == 1 {
+            return sorted[0];
+        }
+        let pos = q * (sorted.len() - 1) as f64;
+        let lower = pos.floor() as usize;
+        let upper = pos.ceil() as usize;
+        if lower == upper {
+            sorted[lower]
+        } else {
+            let frac = pos - lower as f64;
+            sorted[lower] * (1.0 - frac) + sorted[upper] * frac
+        }
+    }
